           // Insert the event into the outbox table
           OrderOutboxEvent outboxEvent = new OrderOutboxEvent();
           outboxEvent.setEventType("ORDER_CREATED");
           outboxEvent.setPayload(order.toJson());

           orderRepository.save(outboxEvent);
       }
   }
