import io.confluent.kafka.schemaregistry.client.SchemaRegistryClient;
import io.confluent.kafka.schemaregistry.client.rest.entities.requests.CompatibilityModeRequest;

public class SchemaRegistration {

    private static final String SCHEMA_REGISTRY_URL = "http://localhost:8081";

    public void registerSchema(String subject, String schemaString) throws Exception {
        SchemaRegistryClient client = new CachedSchemaRegistryClient(SCHEMA_REGISTRY_URL, 100);

        // Set compatibility mode to BACKWARD_TRANSITIVE
        CompatibilityModeRequest request = new CompatibilityModeRequest(CompatibilityMode.BACKWARD_TRANSITIVE.toString());
        client.updateCompatibility(subject, request);

        // Register the schema with the specified subject
        int id = client.register(subject, schemaString.getBytes(), null);
        System.out.println("Registered schema ID: " + id);
    }
}
```

