### 3. Database Locking or Distributed Locks
Use locks to ensure that compensations are only applied once.

#### Example: Using a Distributed Lock

```java
@Service
public class OrderService {

    @Autowired
    private KafkaTemplate<String, String> kafkaTemplate;

    public void createOrder(OrderRequest request) {
        // Create a unique transaction ID
        String transactionId = UUID.randomUUID().toString();

        // Acquire a distributed lock for the transaction ID
        if (acquireLock(transactionId)) {
            try {
                // Create the order in the database
                Long orderId = saveOrder(request);

                // Send a message to Payment Service with the transaction ID
                kafkaTemplate.send("payment-request-topic", "PAYMENT_REQUEST", transactionId, orderId.toString());

                // Send a message to Inventory Service with the transaction ID
                kafkaTemplate.send("inventory-reservation-topic", "INVENTORY_RESERVE", transactionId, orderId.toString());
            } finally {
                releaseLock(transactionId);
            }
        }
    }

    @KafkaListener(topics = "order-payment-failure-topic")
    public void handlePaymentFailure(String transactionId) {
        if (acquireLock(transactionId)) {
            try {
                cancelOrder(transactionId);
                refundPayment(transactionId);
            } finally {
                releaseLock(transactionId);
            }
        }
    }

    @KafkaListener(topics = "order-inventory-failure-topic")
    public void handleInventoryFailure(String transactionId) {
        if (acquireLock(transactionId)) {
            try {
                cancelOrder(transactionId);
                refundPayment(transactionId);
            } finally {
                releaseLock(transactionId);
            }
        }
    }

    private Long saveOrder(OrderRequest request) {
        // Logic to create and persist the order in the database
        return 1L; // Example order ID
    }

    private void cancelOrder(String transactionId) {
        if (!hasAlreadyCanceledOrder(transactionId)) {
            // Logic to cancel the order in the database
            markAsCancelled(transactionId);
        }
    }

    private void refundPayment(String transactionId) {
        if (!hasAlreadyRefundedPayment(transactionId)) {
            // Logic to refund the payment
            kafkaTemplate.send("refund-request-topic", "REFUND_REQUEST", transactionId);
